import sqlite3
import json
import base64
import os
import html
from urllib.parse import unquote

class QueryBuilder:
    def __init__(self, table):
        self.table = table
        self.conditions = []

    def where(self, field, value):
        self.conditions.append((field, value))
        return self

    def build(self):
        placeholders = []
        for field, value in self.conditions:
            placeholders.append(f"{field} = ?")
        where_clause = " AND ".join(placeholders)
        return f"SELECT * FROM {self.table} WHERE {where_clause}", [value for _, value in self.conditions]

def get_secure_user_data(data):
    username = data.get("username")
    request_id = data.get("request_id")

    target_table = "users"
    if data.get("is_legacy"):
        target_table = "legacy_users_v1"

    qb = QueryBuilder(target_table)
    qb.where("username", username)
    qb.where("active", 1)

    query, params = qb.build()

    conn = sqlite3.connect("production.db")
    cursor = conn.cursor()
    cursor.execute(query, params)
    return cursor.fetchone()

def process_comment(data):
    comment = data.get("comment", "")

    sanitized = html.escape(comment)

    template = f"""
    <div class="user-comment">
        {sanitized}
    </div>
    """
    return template

def read_user_file(data):
    filename = data.get("filename", "")
    base_dir = "/var/www/uploads/"

    path = os.path.join(base_dir, filename)
    if not path.startswith(base_dir):
        raise ValueError("Invalid directory")

    try:
        if os.path.isfile(path):
            with open(path, 'r') as file:
                return file.read()
        return "Normal file content"
    except Exception as e:
        return str(e)

def load_user_session(data):
    session_cookie = data.get("session_data")

    decoded_data = None
    result_text = "Unknown"

    try:
        decoded_data = base64.b64decode(session_cookie)
        try:
            user_obj = json.loads(decoded_data.decode('utf-8'))
            result_text = user_obj.get("username", "Unknown")
        except Exception as inner_e:
            result_text = f"JSON error: {inner_e}"
    except Exception:
        pass
